<?php namespace App\Repositories\FrontOffice;use App\Repositories\BaseRepository;use App\Models\FrontOffice\Appointment;use Illuminate\Database\Eloquent\Collection;class AppointmentRepository extends BaseRepository{    public function __construct(Appointment $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function findByVisitor(string $visitorName): Collection    {        return $this->query()->where('visitor_name', 'like', "%{$visitorName}%")->get();    }    public function getByDate(string $date): Collection    {        return $this->query()->whereDate('appointment_date', $date)->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('appointment_date', [$startDate, $endDate])->get();    }    public function getByEmployee(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function getTodayAppointments(): Collection    {        return $this->query()->whereDate('appointment_date', now())->orderBy('start_time', 'asc')->get();    }    public function getPendingAppointments(): Collection    {        return $this->query()->where('status', 'pending')->whereDate('appointment_date', '>=', now())->get();    }    public function confirmAppointment(int $id): bool    {        return $this->update($id, ['status' => 'confirmed']);    }    public function cancelAppointment(int $id, string $reason = null): bool    {        $data = ['status' => 'cancelled'];        if ($reason) {            $data['cancellation_reason'] = $reason;        }        return $this->update($id, $data);    }    public function completeAppointment(int $id): bool    {        return $this->update($id, ['status' => 'completed']);    }    public function checkAvailability(int $employeeId, string $date, string $startTime, string $endTime): bool    {        return $this->query()->where('employee_id', $employeeId)->whereDate('appointment_date', $date)->whereIn('status', ['confirmed', 'pending'])->where(function ($q) use ($startTime, $endTime) {                $q->whereBetween('start_time', [$startTime, $endTime])->orWhereBetween('end_time', [$startTime, $endTime]);            })->exists();    }}